 98	
 99	    it('handles alert close action', () => {
100	      render(<Connectors />);
101	
102	      fireEvent.click(screen.getByTestId('connector-alert-close'));
103	      expect(sessionStorage.getItem('showConnectorAlert')).toBe('hide');
